INSERT INTO `elearning_course` VALUES (51,'Python cơ bản cho người mới bắt đầu','Nắm chắc cú pháp Python, kiểu dữ liệu và cách viết chương trình sạch, dễ bảo trì.','2026-03-23 12:16:12.233959',1,57),(52,'Thiết kế cơ sở dữ liệu với MySQL','Học chuẩn hóa dữ liệu, tối ưu truy vấn SQL và xây dựng schema phù hợp hệ thống thực tế.','2026-03-23 12:16:12.258299',1,58),(53,'Xây dựng Django REST API từ A đến Z','Triển khai API hoàn chỉnh với xác thực, phân quyền, phân trang và tài liệu hóa endpoint.','2026-03-23 12:16:12.277074',1,59),(54,'Kiểm thử phần mềm thực chiến','Thực hành unit test, integration test và chiến lược đảm bảo chất lượng cho backend.','2026-03-23 12:16:12.293769',1,60),(55,'JavaScript hiện đại cho lập trình web','Sử dụng ES6+, async/await và modular code để phát triển giao diện hiệu quả.','2026-03-23 12:16:12.310088',1,61),(56,'Phân tích dữ liệu với Pandas','Làm sạch, trực quan hóa và phân tích dữ liệu bằng Python cho các bài toán nghiệp vụ.','2026-03-23 12:16:12.328997',1,57),(57,'UI/UX căn bản cho lập trình viên','Hiểu tư duy thiết kế trải nghiệm người dùng để phối hợp tốt giữa dev và designer.','2026-03-23 12:16:12.353618',1,58),(58,'Thuật toán và cấu trúc dữ liệu nền tảng','Rèn luyện tư duy giải quyết vấn đề với các cấu trúc dữ liệu và thuật toán phổ biến.','2026-03-23 12:16:12.370907',1,59),(59,'Git và quy trình làm việc nhóm','Làm chủ Git flow, code review và xử lý xung đột khi phát triển theo nhóm.','2026-03-23 12:16:12.389603',1,60),(60,'Triển khai ứng dụng với Docker','Đóng gói, cấu hình và triển khai ứng dụng nhất quán từ local lên môi trường server.','2026-03-23 12:16:12.408004',1,61);
