  KEY `elearning_submission_student_id_32a38b59_fk_elearning_user_id` (`student_id`),
  CONSTRAINT `elearning_submission_assignment_id_ecd96b41_fk_elearning` FOREIGN KEY (`assignment_id`) REFERENCES `elearning_assignment` (`id`),
  CONSTRAINT `elearning_submission_student_id_32a38b59_fk_elearning_user_id` FOREIGN KEY (`student_id`) REFERENCES `elearning_user` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2451 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
